function calculateInventory(products) {
  const results = products.map(p => {
    const taxRate = p.category === 'luxury' ? 0.25 : 0.11;
    const discountedPrice = p.price * (1 - p.discount);
    const finalPrice = discountedPrice * (1 + taxRate);

    return {
      name: p.name,
      stockValue: p.stock * finalPrice,
      isLowStock: p.stock < 10
    };
  });

  return results.filter(r => r.stockValue > 1000);
}

def process_data(users):
    processed = []
    for user in users:
        if user['active']:
            name = user['name'].strip().title()
            score = sum(user['scores']) / len(user['scores'])

            entry = {
                'id': user['id'],
                'display_name': name,
                'average_score': round(score, 2),
                'status': 'honor_roll' if score > 90 else 'passed'
            }
            processed.append(entry)

    return sorted(processed, key=lambda x: x['average_score'], reverse=True)

async function fetchData(url, retries = 3) {
  for (let i = 0; i < retries; i++) {
    try {
      const response = await fetch(url);
      if (!response.ok) throw new Error(`HTTP ${response.status}`);
      const data = await response.json();
      return data.map(item => ({
        id: item.id,
        name: item.full_name.toUpperCase(),
        timestamp: new Date().toISOString(),
        isValid: !!item.full_name
      }));
    } catch (err) {
      if (i === retries - 1) console.error('Final attempt failed:', err);
      await new Promise(resolve => setTimeout(resolve, 1000));
    }
  }
}

