def reverse_list(head):
    prev = None
    current = head
    while current:
        next_node = current.next
        current.next = prev
        prev = current
        current = next_node
    return prev

def print_list(head):
    curr = head
    while curr:
        print(f"{curr.value} -> ", end="")
        curr = curr.next
